import * as React from "react";
import {
  Box,
  Card,
  CardMedia,
  CardContent,
  CardActions,
  Typography,
  Button,
  Chip,
  Avatar,
  AvatarGroup,
  IconButton,
  Grid,
  OutlinedInput,
  InputAdornment,
} from "@mui/material";
import SearchRoundedIcon from "@mui/icons-material/SearchRounded";
import RssFeedRoundedIcon from "@mui/icons-material/RssFeedRounded";

const cardData = [
  {
    category: "WEB APPS",
    img: "https://picsum.photos/800/450?random=1",
    tag: "Engineering",
    title: "Revolutionizing software development with cutting-edge tools",
    description:
      "Our latest engineering tools are designed to streamline workflows and boost productivity.",
    authors: [
      { name: "Remy Sharp", avatar: "/static/images/avatar/1.jpg" },
      { name: "Travis Howard", avatar: "/static/images/avatar/2.jpg" },
    ],
  },
  {
    category: "WEB3/BLOCKCHAIN APPS",
    img: "https://picsum.photos/800/450?random=9",
    tag: "Blockchain",
    title: "Building decentralized applications for the future",
    description:
      "Explore the power of decentralized applications (dApps) and how they are transforming industries.",
    authors: [{ name: "Anna Walker", avatar: "/static/images/avatar/10.jpg" }],
  },
];

function Search({ searchValue, setSearchValue }) {
  return (
    <OutlinedInput
      size="small"
      placeholder="Search…"
      value={searchValue}
      onChange={(e) => setSearchValue(e.target.value)}
      startAdornment={
        <InputAdornment position="start">
          <SearchRoundedIcon fontSize="small" />
        </InputAdornment>
      }
      inputProps={{ "aria-label": "search" }}
    />
  );
}

export default function Projects() {
  const [selectedCategory, setSelectedCategory] = React.useState("All");
  const [searchValue, setSearchValue] = React.useState("");

  const categories = ["All", ...new Set(cardData.map((card) => card.category))];

  const filteredCards = cardData.filter((card) => {
    const matchesCategory = selectedCategory === "All" || card.category === selectedCategory;
    const matchesSearch =
      card.title.toLowerCase().includes(searchValue.toLowerCase()) ||
      card.description.toLowerCase().includes(searchValue.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, maxWidth: 1200, margin: '0 auto', padding: '0 20px', position: 'relative', overflow: 'hidden' }}>
    <Typography variant="h5">Projects</Typography>
    <Typography>Stay in the loop with the latest about our products</Typography>

    <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
      {categories.map(category => (
        <Chip
          key={category}
          label={category}
          clickable
          sx={{ backgroundColor: selectedCategory === category ? 'tomato' : 'lightgray', color: 'white' }}
          onClick={() => {
            setSelectedCategory(category);
            setSearchValue('');
          }}
        />
      ))}
    </Box>

    <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
      <Search searchValue={searchValue} setSearchValue={setSearchValue} />
      <IconButton size="small" aria-label="RSS feed">
        <RssFeedRoundedIcon />
      </IconButton>
    </Box>

    <Grid container spacing={2} mt={3}>
      {filteredCards.map((project, index) => (
        <Grid item xs={12} sm={6} md={4} key={index}>
          <Card sx={{ border: '1px solid var(--border)', overflow: 'hidden' }}>
            <CardMedia
              component="img"
              height="200"
              image={project.img}
              alt={project.title}
              sx={{ objectFit: 'cover' }}
            />
            <CardContent sx={{ borderTop: '1px solid var(--border)', borderBottom: '1px solid var(--border)', padding: '8px', color: 'var(--secondary-text)', fontSize: '14px' }}>
              <Typography variant="caption">{project.category}</Typography>
            </CardContent>
            <CardContent>
              <Typography variant="h6">{project.title}</Typography>
              <Typography variant="body2" color="text.secondary">{project.description}</Typography>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, marginTop: 2 }}>
                <AvatarGroup max={3}>
                  {project.authors.map((author, i) => (
                    <Avatar key={i} alt={author.name} src={author.avatar} sx={{ width: 24, height: 24 }} />
                  ))}
                </AvatarGroup>
                <Typography variant="caption">{project.authors.map(a => a.name).join(', ')}</Typography>
              </Box>
            </CardContent>
          </Card>
        </Grid>
      ))}
    </Grid>
  </Box>
  );
}
